import React, { useEffect, useState } from "react";
import { Table, Select, Button, Avatar, Card, Tooltip, Switch, message } from "antd";
import {
  Search,
  Eye,
  Edit,
  Trash2,
  Mail,
  Phone,
  Activity,
  MoreVertical,
  Filter,
  Download,
  Building2,
  ShieldCheck,
} from "lucide-react";
import { useDispatch, useSelector } from "react-redux";
import axios from "axios";
import { base_url } from "../../utils/baseUrl";
import { config } from "../../utils/axiosconfig";
import {
  deleteUser,
  getUsers,
  updateUserStatus,
} from "../../features/UserList/UserListSlice";
import { useNavigate } from "react-router-dom";
import CustomModal from "../../components/CustomModal";

const { Option } = Select;

const UserList = ({ role }) => {
  const [open, setOpen] = useState(false);
  const [userId, setUserId] = useState("");
  const [searchText, setSearchText] = useState("");
  const [selectedRowKeys, setSelectedRowKeys] = useState([]);
  const [loadingEmail, setLoadingEmail] = useState({});
  const [loadingB2b, setLoadingB2b] = useState({});
  const [localOverrides, setLocalOverrides] = useState({});
  const dispatch = useDispatch();
  const navigate = useNavigate();

  useEffect(() => {
    dispatch(getUsers(role));
  }, [dispatch, role]);

  const userState = useSelector((state) => state?.userList?.userLists) || {};

  const handleToggleEmail = async (uid) => {
    setLoadingEmail((p) => ({ ...p, [uid]: true }));
    try {
      const res = await axios.put(
        `${base_url}user/toggle-email-verification/${uid}`,
        {},
        config
      );
      const newVal = res.data.isEmailVerified;
      setLocalOverrides((p) => ({ ...p, [uid]: { ...p[uid], isEmailVerified: newVal } }));
      message.success(`Email verification ${newVal ? "enabled" : "disabled"}`);
    } catch {
      message.error("Failed to update email verification");
    } finally {
      setLoadingEmail((p) => ({ ...p, [uid]: false }));
    }
  };

  const handleToggleB2b = async (uid) => {
    setLoadingB2b((p) => ({ ...p, [uid]: true }));
    try {
      const res = await axios.put(`${base_url}user/toggle-b2b/${uid}`, {}, config);
      const newVal = res.data.b2bEnabled;
      setLocalOverrides((p) => ({ ...p, [uid]: { ...p[uid], b2bEnabled: newVal } }));
      message.success(`B2B access ${newVal ? "enabled" : "disabled"}`);
    } catch {
      message.error("Failed to update B2B access");
    } finally {
      setLoadingB2b((p) => ({ ...p, [uid]: false }));
    }
  };

  const showModal = (id) => { setOpen(true); setUserId(id); };
  const hideModal = () => setOpen(false);
  const handleChangeStatus = (value, uid) => {
    dispatch(updateUserStatus({ id: uid, status: value === "active", role }));
  };
  const deleteUserHandler = (id) => {
    dispatch(deleteUser({ userId: id, role }));
    setOpen(false);
    setTimeout(() => dispatch(getUsers(role)), 500);
  };

  const columns = [
    {
      title: "IDENTITY",
      dataIndex: "name",
      width: 280,
      render: (_, record) => (
        <div className="flex items-center gap-4">
          <div className="relative">
            <Avatar
              size={52}
              src={`https://api.dicebear.com/7.x/initials/svg?seed=${record.firstname}&backgroundColor=f1f5f9&textColor=2563eb`}
              className="rounded-2xl border-2 border-white shadow-md ring-1 ring-slate-100"
            />
            <div className={`absolute -bottom-1 -right-1 w-3.5 h-3.5 rounded-full border-2 border-white ${record.isActive ? "bg-emerald-500" : "bg-slate-300"}`} />
          </div>
          <div>
            <span className="font-extrabold text-slate-900 text-[15px] leading-tight block">
              {record.firstname} {record.lastname}
            </span>
            <span className="text-[10px] font-black text-blue-600 bg-blue-50 border border-blue-100 px-2 py-0.5 rounded-md uppercase tracking-wider">
              {role}
            </span>
          </div>
        </div>
      ),
      sorter: (a, b) => a.firstname.localeCompare(b.firstname),
    },
    {
      title: "CONTACT",
      render: (_, record) => (
        <div className="flex flex-col gap-1.5">
          <div className="flex items-center gap-2 text-slate-600 font-semibold text-[13px]">
            <Mail size={12} className="text-slate-400" /> {record.email}
          </div>
          <div className="flex items-center gap-2 text-slate-500 font-semibold text-[13px]">
            <Phone size={12} className="text-slate-400" /> {record.mobile}
          </div>
        </div>
      ),
    },
    {
      title: "EMAIL VERIFIED",
      width: 130,
      render: (_, record) => (
        <div className="flex flex-col items-center gap-1">
          <Switch
            checked={record.isEmailVerified}
            loading={!!loadingEmail[record.userId]}
            onChange={() => handleToggleEmail(record.userId)}
            checkedChildren="✓"
            unCheckedChildren="✗"
            style={{ backgroundColor: record.isEmailVerified ? "#10b981" : undefined }}
          />
          <span className="text-[9px] font-black uppercase tracking-wider text-slate-400">
            {record.isEmailVerified ? "Verified" : "Pending"}
          </span>
        </div>
      ),
    },
    {
      title: "B2B ACCESS",
      width: 120,
      render: (_, record) => (
        <div className="flex flex-col items-center gap-1">
          <Switch
            checked={record.b2bEnabled}
            loading={!!loadingB2b[record.userId]}
            onChange={() => handleToggleB2b(record.userId)}
            checkedChildren="ON"
            unCheckedChildren="OFF"
            style={{ backgroundColor: record.b2bEnabled ? "#3b82f6" : undefined }}
          />
          <span className="text-[9px] font-black uppercase tracking-wider text-slate-400">
            {record.b2bEnabled ? "Enabled" : "Disabled"}
          </span>
        </div>
      ),
    },
    {
      title: "STATUS",
      width: 170,
      render: (_, record) => (
        <Select
          defaultValue={record.isActive ? "active" : "inactive"}
          className="w-full modern-select-v2"
          bordered={false}
          suffixIcon={<MoreVertical size={13} className="text-slate-400" />}
          onChange={(value) => handleChangeStatus(value, record.userId)}
        >
          <Option value="active">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-emerald-500" />
              <span className="text-[11px] font-black text-slate-700 uppercase tracking-wider">Active</span>
            </div>
          </Option>
          <Option value="inactive">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-slate-400" />
              <span className="text-[11px] font-black text-slate-700 uppercase tracking-wider">Restricted</span>
            </div>
          </Option>
        </Select>
      ),
    },
    {
      title: "ACTIONS",
      width: 130,
      align: "right",
      render: (_, record) => (
        <div className="flex items-center justify-end gap-1 pr-2">
          <Tooltip title="View Profile">
            <Button
              type="text"
              icon={<Eye size={18} />}
              className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl w-10 h-10 flex items-center justify-center"
              onClick={() => navigate(`/superAdmin/Profile/${record.userId}`)}
            />
          </Tooltip>
          {role === "merchant" && (
            <Tooltip title="Manage Stores">
              <Button
                type="text"
                icon={<Edit size={18} />}
                className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl w-10 h-10 flex items-center justify-center"
                onClick={() => navigate(`/superAdmin/merchantList/list-Store/${record.userId}`)}
              />
            </Tooltip>
          )}
          <Tooltip title="Delete">
            <Button
              type="text"
              danger
              icon={<Trash2 size={18} />}
              className="text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl w-10 h-10 flex items-center justify-center"
              onClick={() => showModal(record.userId)}
            />
          </Tooltip>
        </div>
      ),
    },
  ];

  const data = (Array.isArray(userState.users) ? userState.users : [])
    .filter(
      (user) =>
        !searchText ||
        `${user.firstname} ${user.lastname}`.toLowerCase().includes(searchText.toLowerCase()) ||
        user.email.toLowerCase().includes(searchText.toLowerCase())
    )
    .map((user, index) => {
      const uid = user._id || user.id;
      const ov = localOverrides[uid] || {};
      return {
        key: uid || index + 1,
        userId: uid,
        firstname: user.firstname,
        lastname: user.lastname,
        email: user.email,
        mobile: user.mobile,
        isActive: user.isActive,
        isEmailVerified: ov.isEmailVerified !== undefined ? ov.isEmailVerified : (user.isEmailVerified || false),
        b2bEnabled: ov.b2bEnabled !== undefined ? ov.b2bEnabled : !!(user.customerType),
      };
    });

  return (
    <div className="space-y-8 pb-20">
      {/* Header */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-end">
        <div className="lg:col-span-2">
          <div className="flex items-center gap-3 mb-3">
            <div className="px-3 py-1 bg-blue-600 rounded-lg text-white font-black text-[10px] uppercase tracking-widest">
              Live System
            </div>
            <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
          </div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight leading-none mb-3">
            {role} <span className="text-blue-600">Archive</span>
          </h1>
          <p className="text-[15px] text-slate-500 font-semibold max-w-xl">
            Manage email verification, B2B access, and account status for {role} accounts.
          </p>
        </div>
        <div className="flex flex-col gap-3">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
            <input
              type="text"
              placeholder={`Search ${role} accounts...`}
              className="pl-12 pr-5 h-14 w-full bg-white border-2 border-slate-100 rounded-2xl focus:outline-none focus:border-blue-500 text-[14px] font-semibold"
              onChange={(e) => setSearchText(e.target.value)}
            />
          </div>
          <div className="flex gap-2">
            <Button className="flex-1 h-11 rounded-xl border-slate-200 font-bold text-[11px] uppercase text-slate-500 flex items-center justify-center gap-1.5">
              <Filter size={13} /> Filter
            </Button>
            <Button className="flex-1 h-11 rounded-xl border-slate-200 font-bold text-[11px] uppercase text-slate-500 flex items-center justify-center gap-1.5">
              <Download size={13} /> Export
            </Button>
          </div>
        </div>
      </div>

      <Card className="rounded-3xl border-none shadow-xl overflow-hidden bg-white">
        <div className="flex justify-between items-center px-8 py-5 border-b border-slate-50 bg-slate-50/30">
          <div className="flex items-center gap-4">
            <span className="text-[13px] font-black text-slate-900 uppercase">Total</span>
            <span className="bg-blue-600 text-white text-[11px] font-black px-2.5 py-0.5 rounded-full">
              {data.length}
            </span>
          </div>
          <div className="flex items-center gap-2 text-slate-400 font-bold text-[11px] uppercase tracking-widest">
            <Activity size={13} /> Health: <span className="text-emerald-500 ml-1">Optimal</span>
          </div>
        </div>

        <Table
          rowSelection={{ selectedRowKeys, onChange: setSelectedRowKeys }}
          columns={columns}
          dataSource={data}
          pagination={{ pageSize: 10, className: "px-8 py-6 border-t border-slate-50" }}
          className="premium-table"
          scroll={{ x: 1200 }}
        />
      </Card>

      <CustomModal
        hideModal={hideModal}
        open={open}
        performAction={() => deleteUserHandler(userId)}
        title="Revoke Access"
        content={`This will permanently remove the ${role} account. This action cannot be undone.`}
      />

      <style>{`
        .premium-table .ant-table-thead > tr > th {
          background: #fafbfc !important; color: #94a3b8 !important;
          font-weight: 800 !important; font-size: 10px !important;
          text-transform: uppercase !important; letter-spacing: 0.12em !important;
          padding: 18px 24px !important; border-bottom: 2px solid #f1f5f9 !important;
        }
        .premium-table .ant-table-tbody > tr > td {
          padding: 18px 24px !important; border-bottom: 1px solid #f8fafc !important;
        }
        .premium-table .ant-table-tbody > tr:hover > td { background: #fdfdfe !important; }
        .modern-select-v2 {
          background: #f8fafc !important; border-radius: 12px !important;
          border: 1.5px solid #e2e8f0 !important; height: 40px !important;
          display: flex !important; align-items: center !important;
        }
        .ant-pagination-item-active { border-color: #2563eb !important; background: #2563eb !important; }
        .ant-pagination-item-active a { color: white !important; }
      `}</style>
    </div>
  );
};

export default UserList;
